import{_ as a,o as d,c as r,ag as e}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"伯克希尔·哈撒韦（Berkshire Hathaway）","description":"","frontmatter":{},"headers":[],"relativePath":"03_companies/伯克希尔哈撒韦.md","filePath":"03_companies/伯克希尔哈撒韦.md"}'),l={name:"03_companies/伯克希尔哈撒韦.md"};function h(o,t,i,n,s,b){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="伯克希尔·哈撒韦-berkshire-hathaway" tabindex="-1">伯克希尔·哈撒韦（Berkshire Hathaway） <a class="header-anchor" href="#伯克希尔·哈撒韦-berkshire-hathaway" aria-label="Permalink to &quot;伯克希尔·哈撒韦（Berkshire Hathaway）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>英文名</td><td>Berkshire Hathaway Inc.</td></tr><tr><td>行业</td><td>多元化投资控股</td></tr><tr><td>成立</td><td>1839年（纺织厂），1965年（巴菲特控制）</td></tr><tr><td>总部</td><td>内布拉斯加州奥马哈</td></tr><tr><td>股票代码</td><td>NYSE: BRK.A, BRK.B</td></tr></tbody></table><h2 id="发展历程" tabindex="-1">发展历程 <a class="header-anchor" href="#发展历程" aria-label="Permalink to &quot;发展历程&quot;">​</a></h2><h3 id="纺织时代-1839-1985" tabindex="-1">纺织时代（1839-1985） <a class="header-anchor" href="#纺织时代-1839-1985" aria-label="Permalink to &quot;纺织时代（1839-1985）&quot;">​</a></h3><ul><li>1839年：河谷瀑布公司（纺织厂）</li><li>1955年：伯克希尔与哈撒韦合并</li><li>1965年：巴菲特取得控制权（股价约$12）</li><li>1985年：关闭纺织业务</li></ul><h3 id="转型时代-1967-1980年代" tabindex="-1">转型时代（1967-1980年代） <a class="header-anchor" href="#转型时代-1967-1980年代" aria-label="Permalink to &quot;转型时代（1967-1980年代）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>事件</th></tr></thead><tbody><tr><td>1967</td><td>收购国家赔偿公司（保险）</td></tr><tr><td>1972</td><td>收购喜诗糖果（通过蓝筹印花）</td></tr><tr><td>1983</td><td>蓝筹印花与伯克希尔合并</td></tr><tr><td>1985</td><td>关闭纺织，全面转向投资</td></tr><tr><td>1985</td><td>投资首都城市/ABC（$517.5M）</td></tr><tr><td>1987</td><td>投资所罗门兄弟（$700M优先股）</td></tr></tbody></table><h3 id="财务里程碑" tabindex="-1">财务里程碑 <a class="header-anchor" href="#财务里程碑" aria-label="Permalink to &quot;财务里程碑&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>每股净值</th><th>年复利增长</th></tr></thead><tbody><tr><td>1965</td><td>$4</td><td>-</td></tr><tr><td>1985</td><td>$1,200+</td><td>约22%</td></tr><tr><td>1987</td><td>$2,477</td><td>23%+</td></tr></tbody></table><h2 id="核心业务板块" tabindex="-1">核心业务板块 <a class="header-anchor" href="#核心业务板块" aria-label="Permalink to &quot;核心业务板块&quot;">​</a></h2><h3 id="_1-保险业务" tabindex="-1">1. 保险业务 <a class="header-anchor" href="#_1-保险业务" aria-label="Permalink to &quot;1. 保险业务&quot;">​</a></h3><ul><li><strong>国家赔偿公司</strong>：1967年收购，承保纪律严格</li><li><strong>GEICO</strong>：约35-41%持股，最大非控股持仓</li><li><strong>其他保险子公司</strong>：Fireman&#39;s Fund份额参与等</li></ul><h3 id="_2-实业控股" tabindex="-1">2. 实业控股 <a class="header-anchor" href="#_2-实业控股" aria-label="Permalink to &quot;2. 实业控股&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>行业</th><th>收购年份</th></tr></thead><tbody><tr><td>喜诗糖果</td><td>糖果零售</td><td>1972</td></tr><tr><td>内布拉斯加家具城</td><td>家具零售</td><td>1983</td></tr><tr><td>水牛城新闻</td><td>报纸</td><td>1977</td></tr><tr><td>Scott &amp; Fetzer</td><td>多元制造</td><td>1985</td></tr><tr><td>Fechheimer Bros.</td><td>制服</td><td>1986</td></tr></tbody></table><h3 id="_3-股权投资" tabindex="-1">3. 股权投资 <a class="header-anchor" href="#_3-股权投资" aria-label="Permalink to &quot;3. 股权投资&quot;">​</a></h3><ul><li><strong>华盛顿邮报</strong>：1973年买入</li><li><strong>首都城市/ABC</strong>：1985年买入</li><li><strong>所罗门兄弟</strong>：1987年优先股</li><li><strong>其他主要持仓</strong>：通用食品、时代公司等</li></ul><h2 id="管理哲学" tabindex="-1">管理哲学 <a class="header-anchor" href="#管理哲学" aria-label="Permalink to &quot;管理哲学&quot;">​</a></h2><h3 id="核心原则-1983年附录" tabindex="-1">核心原则（1983年附录） <a class="header-anchor" href="#核心原则-1983年附录" aria-label="Permalink to &quot;核心原则（1983年附录）&quot;">​</a></h3><ol><li>虽然形式上是公司，但实际上是合伙人关系</li><li>董事会大多数成员持有大量股份</li><li>长期经营，不关心季度业绩</li><li>资本配置集权，运营管理分权</li></ol><h3 id="管理架构" tabindex="-1">管理架构 <a class="header-anchor" href="#管理架构" aria-label="Permalink to &quot;管理架构&quot;">​</a></h3><ul><li><strong>总部</strong>：仅20余人（1987年）</li><li><strong>资本配置</strong>：巴菲特负责</li><li><strong>运营管理</strong>：子公司经理人全权负责</li></ul><h2 id="巴菲特评价摘录" tabindex="-1">巴菲特评价摘录 <a class="header-anchor" href="#巴菲特评价摘录" aria-label="Permalink to &quot;巴菲特评价摘录&quot;">​</a></h2><blockquote><p>&quot;伯克希尔的股东应该知道，我和查理把你们的钱当自己的钱管理。&quot; —— 1983年股东信</p></blockquote><blockquote><p>&quot;我们只做自己理解的事，我们的能力圈很窄但很明确。&quot; —— 多次提及</p></blockquote><blockquote><p>&quot;资本配置是CEO唯一不可委托的工作。&quot; —— 1987年股东信</p></blockquote><h2 id="历史业绩-摘录" tabindex="-1">历史业绩（摘录） <a class="header-anchor" href="#历史业绩-摘录" aria-label="Permalink to &quot;历史业绩（摘录）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>每股净值</th><th>增长率</th></tr></thead><tbody><tr><td>1965</td><td>$4</td><td>-</td></tr><tr><td>1978</td><td>$737</td><td>-</td></tr><tr><td>1985</td><td>$1,515</td><td>48.2%</td></tr><tr><td>1987</td><td>$2,477</td><td>19.5%</td></tr></tbody></table><p><strong>1965-1987年复利增长率：约23%</strong></p><h2 id="在股东信中的角色" tabindex="-1">在股东信中的角色 <a class="header-anchor" href="#在股东信中的角色" aria-label="Permalink to &quot;在股东信中的角色&quot;">​</a></h2><p>每封股东信的主题，1977-2024年共48封。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../04_人物库/沃伦·巴菲特">沃伦·巴菲特</a> - 董事长兼CEO</li><li><a href="./../04_人物库/查理·芒格">查理·芒格</a> - 副董事长</li><li><a href="./GEICO">GEICO</a> - 最大非控股持仓</li><li><a href="./国家赔偿公司">国家赔偿公司</a> - 首个保险收购</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',35)])])}const q=a(l,[["render",h]]);export{c as __pageData,q as default};
